#!/usr/bin/env bash
set -euo pipefail

# Optional Colab bootstrap for Zodiac attack runtimes.
# Safe to re-run; designed to be idempotent.

ROOT_DEFAULT="/content/emotions"
ROOT="${1:-$ROOT_DEFAULT}"

echo "[colab-bootstrap] repo root: ${ROOT}"

if [[ ! -d "${ROOT}" ]]; then
  echo "[colab-bootstrap] repo not found at ${ROOT}" >&2
  echo "[colab-bootstrap] clone first, e.g.: git clone <repo-url> ${ROOT}" >&2
  exit 1
fi

cd "${ROOT}"

python3 -m pip install --upgrade pip setuptools wheel
python3 -m pip install --upgrade numpy

# Torch is preinstalled on most Colab GPU images; keep this light and only install
# when import fails.
if python3 - <<'PY'
try:
    import torch  # noqa: F401
    print("[colab-bootstrap] torch already available")
except Exception:
    raise SystemExit(1)
PY
then
  :
else
  python3 -m pip install --upgrade torch --index-url https://download.pytorch.org/whl/cu121
fi

if command -v cargo >/dev/null 2>&1; then
  echo "[colab-bootstrap] cargo already available"
else
  echo "[colab-bootstrap] installing rustup/cargo"
  curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y
  # shellcheck disable=SC1091
  source "${HOME}/.cargo/env"
fi

echo "[colab-bootstrap] done"
